remove(id) {
  const index = this.todos.findIndex(todo => todo.id === id);
  if (index !== -1) {
    this.todos.splice(index, 1);
    return true;
  }
  return false;
}

complete(id) {
  const todo = this.todos.find(todo => todo.id === id);
  if (todo) {
    todo.completed = true;
    return true;
  }
  return false;
}

list() {
  return this.todos;
}
